// Generated by GitHub Copilot
const { ipcMain, app, BrowserWindow } = require("electron");
const { randomUUID } = require("node:crypto");
const { z } = require("zod");
const { getEnvironmentConfig } = require("./env-config.cjs");
const { resolveFeatureFlags } = require("./feature-flags.cjs");
const { buildPromptWithPreset, getPromptPresets } = require("./prompt-presets.cjs");

